import Foundation

enum NetworkError: Error {
    case invalidURL
    case noData
    case decodingError
    case authenticationFailed
}

protocol NetworkServiceProtocol {
    func fetchUserData(completion: @escaping (Result<User, NetworkError>) -> Void)
    func authenticate(username: String, password: String, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void)
    func postUserData(_ userData: UserData, completion: @escaping (Result<Bool, NetworkError>) -> Void)
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct AuthResponse: Codable {
    let token: String
    let expires: Date
}

struct UserData: Codable {
    let name: String
    let email: String
}

class NetworkService: NetworkServiceProtocol {
    private let baseURL: URL
    private let session: URLSession
    
    init(environment: Environment = .production) {
        self.baseURL = environment.baseURL
        self.session = URLSession.shared
    }
    
    func fetchUserData(completion: @escaping (Result<User, NetworkError>) -> Void) {
        guard let url = URL(string: "users/me", relativeTo: baseURL) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.decodingError))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let user = try JSONDecoder().decode(User.self, from: data)
                completion(.success(user))
            } catch {
                completion(.failure(.decodingError))
            }
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        guard let url = URL(string: "auth/login", relativeTo: baseURL) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body = ["username": username, "password": password]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.authenticationFailed))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let authResponse = try JSONDecoder().decode(AuthResponse.self, from: data)
                completion(.success(authResponse))
            } catch {
                completion(.failure(.decodingError))
            }
        }
        
        task.resume()
    }
    
    func postUserData(_ userData: UserData, completion: @escaping (Result<Bool, NetworkError>) -> Void) {
        guard let url = URL(string: "users", relativeTo: baseURL) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        request.httpBody = try? JSONEncoder().encode(userData)
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.decodingError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.noData))
                return
            }
            
            if (200...299).contains(httpResponse.statusCode) {
                completion(.success(true))
            } else {
                completion(.failure(.decodingError))
            }
        }
        
